with WithAncestors AS (SELECT itemid FROM AncestorIds2 WHERE AncestorId in (100) )select count(*) OVER() AS TotalRecordCount,A.Id,A.SeriesPresentationUniqueKey from mediaitems A left join UserDatas on A.UserDataKeyId=UserDatas.UserDataKeyId And UserDatas.UserId=1 left join (select N.SeriesPresentationUniqueKey,max(userdatas.lastplayeddateint) as lastplayeddateint from mediaitems N left join UserDatas on N.UserDataKeyId=UserDatas.UserDataKeyId And UserDatas.UserId=1 where N.Type=8 Group by N.SeriesPresentationUniqueKey) LastWatchedEpisodes on LastWatchedEpisodes.SeriesPresentationUniqueKey=A.SeriesPresentationUniqueKey where A.Type=8 AND EXISTS (SELECT 1 FROM AncestorIds2 WHERE AncestorIds2.itemid = A.Id AND AncestorIds2.AncestorId in (100)) Group by coalesce(A.SeriesPresentationUniqueKey, A.PresentationUniqueKey) ORDER BY COALESCE(lastwatchedepisodes.lastplayeddateint, userdatas.lastplayeddateint, 0) DESC,Min(EpisodeAbsoluteIndexNumber) ASC LIMIT 12
